// summarizeResponse wrapper pattern:
export function summarizeResponse<T, S>(items: T[], summarizer: (item: T) => S, note?: string) {
  return {
    total: items.length,
    items: items.map(summarizer),
    note: note ?? "Showing summarized results. Use summary=false for full API response.",
  };
}

// Handler pattern:
handler: async (args) => {
  const { summary = true, ...rest } = args;
  const results = await getProjects(rest);
  if (summary) {
    return jsonResponse(summarizeResponse(results, summarizeProject));
  }
  return jsonResponse(results);
},
